import{_ as i,o,c as e,a2 as t}from"./chunks/framework.c6mn6h8d.js";const h=JSON.parse('{"title":"第二十一章：计算机网络","description":"","frontmatter":{"title":"第二十一章：计算机网络"},"headers":[],"relativePath":"21-network.md","filePath":"21-network.md","lastUpdated":null}'),a={name:"21-network.md"};function r(n,l,s,d,u,c){return o(),e("div",null,[...l[0]||(l[0]=[t(`<h1 id="第二十一章-计算机网络" tabindex="-1">第二十一章：计算机网络 <a class="header-anchor" href="#第二十一章-计算机网络" aria-label="Permalink to &quot;第二十一章：计算机网络&quot;">​</a></h1><h3 id="q-21-1" tabindex="-1">1. TCP三次握手四次挥手（为什么是三次？四次？TIME_WAIT） <a class="header-anchor" href="#q-21-1" aria-label="Permalink to &quot;1. TCP三次握手四次挥手（为什么是三次？四次？TIME_WAIT） {#q-21-1}&quot;">​</a></h3><p><strong>三次握手原因</strong>：TCP是双向通信协议，需要双方确认各自的收发能力正常。第一次握手：客户端发送SYN，服务端知道客户端发送正常；第二次握手：服务端回复SYN+ACK，客户端知道自己收发正常、服务端收发正常；第三次握手：客户端发送ACK，服务端知道自己发送正常、客户端接收正常。如果只有两次，服务端无法确认客户端的接收能力，也无法防止已失效的连接请求报文突然传到服务端导致错误建立连接。三次是理论上的最小值。</p><p><strong>四次挥手原因</strong>：TCP连接是全双工的，每个方向需要单独关闭。一方发送FIN表示&quot;我没有数据要发了&quot;，但对方可能还有数据要发送。所以收到FIN的一方先回复ACK确认，等自己数据发完再发FIN。这导致FIN和ACK分开发送，所以需要四次。如果被动关闭方没有数据要发，可以将ACK和FIN合并，变成三次挥手。</p><p><strong>TIME_WAIT状态</strong>：主动关闭方在发送最后一个ACK后进入TIME_WAIT，持续2MSL（Maximum Segment Lifetime，通常60秒）。作用：(1) 确保最后一个ACK能被对方收到，如果对方没收到会重发FIN，此时主动方可以重发ACK；(2) 让旧连接的所有报文在网络中消失，防止旧报文干扰同端口的新连接。在AI服务高并发场景，如果服务端主动关闭连接过多，会出现大量TIME_WAIT连接耗尽端口，需要调整内核参数（tcp_tw_reuse）或使用长连接。</p><h4 id="f-21-1" tabindex="-1">追问： <a class="header-anchor" href="#f-21-1" aria-label="Permalink to &quot;追问： {#f-21-1}&quot;">​</a></h4><ul><li>追问1：如果第三次握手的ACK丢失，服务端会如何表现，而客户端此时是否已认为自己连接建立成功？ <ul><li><strong>答</strong>：服务端仍处于 SYN_RCVD，未收到第三次 ACK 会重传 SYN+ACK（数次），超时后拆除半连接；客户端发送 ACK 后即认为已 ESTABLISHED 并可能开始发数据，但服务端未确认，数据会被 RST 拒绝或丢弃，直到客户端也超时重连。</li></ul></li><li>追问2：碳管家AI助手的SSE长连接在高并发下产生大量TIME_WAIT，除了tcp_tw_reuse还可通过哪些应用层或架构手段缓解端口耗尽？ <ul><li><strong>答</strong>：从应用层与架构入手： <ul><li>复用长连接、减少频繁建连，客户端/网关使用连接池与 keep-alive；</li><li>由客户端主动关闭，把 TIME_WAIT 转移到客户端而非服务端；</li><li>前置 L7 网关终结连接，后端用长连接池，减少服务端端口消耗；</li><li>容器化水平扩容增加可用端口，并用 SO_REUSEPORT 提升端口复用效率。</li></ul></li></ul></li></ul><h3 id="q-21-2" tabindex="-1">2. HTTP/1.1 vs HTTP/2 vs HTTP/3（多路复用、头部压缩、QUIC） <a class="header-anchor" href="#q-21-2" aria-label="Permalink to &quot;2. HTTP/1.1 vs HTTP/2 vs HTTP/3（多路复用、头部压缩、QUIC） {#q-21-2}&quot;">​</a></h3><table tabindex="0"><thead><tr><th>特性</th><th>HTTP/1.1</th><th>HTTP/2</th><th>HTTP/3</th></tr></thead><tbody><tr><td>传输层</td><td>TCP</td><td>TCP</td><td>QUIC(UDP)</td></tr><tr><td>多路复用</td><td>不支持（队头阻塞）</td><td>支持（流多路复用）</td><td>支持（无队头阻塞）</td></tr><tr><td>头部压缩</td><td>无</td><td>HPACK</td><td>QPACK</td></tr><tr><td>连接建立</td><td>TCP三次握手</td><td>TCP+TLS</td><td>QUIC 0-RTT/1-RTT</td></tr><tr><td>服务器推送</td><td>无</td><td>支持</td><td>支持</td></tr></tbody></table><p><strong>HTTP/2多路复用</strong>：在单个TCP连接上同时传输多个请求/响应流，每个流有独立ID，帧可以交错发送。但TCP层面的队头阻塞问题仍然存在——一个TCP包丢失会导致所有流等待重传。<strong>HTTP/3使用QUIC</strong>：基于UDP，每个流独立传输，一个流的丢包不影响其他流，彻底解决队头阻塞。QUIC在UDP上实现了类似TCP的可靠传输、拥塞控制，并内置TLS 1.3加密。</p><p>在AI助手的场景中，流式输出（SSE）对实时性要求高。HTTP/2能更好地支持并发SSE连接，避免浏览器对同一域名的HTTP/1.1连接数限制（6个），提升用户并发体验。</p><h4 id="f-21-2" tabindex="-1">追问： <a class="header-anchor" href="#f-21-2" aria-label="Permalink to &quot;追问： {#f-21-2}&quot;">​</a></h4><ul><li>追问1：HTTP/2仍受TCP层队头阻塞影响，在弱网环境下流式推送token时可能比预期更慢，如何评估与验证这一影响？ <ul><li><strong>答</strong>：可量化验证： <ul><li>用 <code>tc netem</code> 注入丢包/延迟模拟弱网，对比 HTTP/2 与 HTTP/3 的 SSE 首/末 token 延迟与抖动；</li><li>Wireshark 抓 <code>tcp.analysis.retransmission</code>，统计单流丢包对其他流造成的阻塞时长；</li><li>前端埋点记录流式完成时间，量化队头阻塞影响，再评估是否值得启用 HTTP/3/QUIC。</li></ul></li></ul></li><li>追问2：碳管家若从HTTP/2升级到基于QUIC的HTTP/3，在现有Nginx与Spring Boot技术栈上需要做哪些改造？ <ul><li><strong>答</strong>： <ul><li>Nginx 启用 QUIC 模块（<code>listen 443 quic</code>、<code>http3 on</code>），同时保留 HTTP/2 兼容，并配置 <code>Alt-Svc</code> 指示；</li><li>通常由网关终结 HTTP/3 后转 HTTP/2 给后端 Spring Boot，后端无需直接支持 UDP/QUIC；</li><li>确认 LB 支持 UDP 转发与健康检查，证书与 DNS 不变。</li></ul></li></ul></li></ul><h3 id="q-21-3" tabindex="-1">3. HTTPS原理（SSL/TLS握手、证书链、双向认证） <a class="header-anchor" href="#q-21-3" aria-label="Permalink to &quot;3. HTTPS原理（SSL/TLS握手、证书链、双向认证） {#q-21-3}&quot;">​</a></h3><p><strong>TLS握手流程（1.2版本）</strong>：</p><ol><li>Client Hello：客户端发送支持的加密套件、随机数</li><li>Server Hello：服务端选择加密套件，发送证书和随机数</li><li>客户端验证证书链，生成Pre-Master Secret，用服务端公钥加密发送</li><li>双方根据三个随机数生成会话密钥</li><li>切换为对称加密通信</li></ol><p><strong>TLS 1.3优化</strong>：握手减到1-RTT，移除RSA密钥交换，只保留前向安全的DH密钥交换。内网微服务间通信可使用mTLS双向认证。</p><p><strong>证书链</strong>：根证书（自签名，预置在操作系统/浏览器）→ 中间证书（根CA签发）→ 服务器证书。验证时逐级向上检查签名直到信任锚点。</p><p><strong>双向认证（mTLS）</strong>：不仅服务端出示证书，客户端也出示证书。在AI微服务架构中，服务间调用使用mTLS确保只有授权服务能访问，例如AI网关验证调用方身份后才转发到模型推理服务，防止未授权访问。</p><h4 id="f-21-3" tabindex="-1">追问： <a class="header-anchor" href="#f-21-3" aria-label="Permalink to &quot;追问： {#f-21-3}&quot;">​</a></h4><ul><li>追问1：TLS 1.3将握手降至1-RTT，但证书链验证失败的常见根因有哪些，如何在Spring Boot中快速定位？ <ul><li><strong>答</strong>：常见根因：证书链不完整（缺中间证书）、JVM 信任库 cacerts 过期未含根 CA、证书域名/SAN 与 host 不匹配、证书过期。定位：开启 <code>-Djavax.net.debug=ssl:handshake</code> 看握手日志；用 <code>openssl s_client -connect host:443</code> 验证链；检查 <code>server.ssl.trust-store</code> 与证书有效期。</li></ul></li><li>追问2：碳管家内部微服务间采用mTLS双向认证，当某个服务证书过期时，应如何设计无停机轮换机制？ <ul><li><strong>答</strong>： <ul><li>服务支持热加载证书（监听文件变更或定时重载 SSLContext），无需重启；</li><li>采用重叠有效期：新证书提前签发，旧证书在宽限期内仍有效，滚动重启逐个实例；</li><li>结合 K8s 滚动更新 + 就绪探针，新实例用新证书通过 mTLS 健康检查后再下线旧实例；</li><li>用 cert-manager 自动续期并触发优雅重载。</li></ul></li></ul></li></ul><h3 id="q-21-4" tabindex="-1">4. WebSocket vs SSE vs 长轮询（AI流式输出场景选型） <a class="header-anchor" href="#q-21-4" aria-label="Permalink to &quot;4. WebSocket vs SSE vs 长轮询（AI流式输出场景选型） {#q-21-4}&quot;">​</a></h3><p><strong>SSE（Server-Sent Events）</strong>：服务端到客户端的单向流，基于HTTP协议，自动重连，浏览器原生支持EventSource API。是AI流式输出的最佳选择——LLM逐token生成时通过SSE推送到前端，实现打字机效果。碳管家助手中，用户提问后SSE推送每个token，前端实时渲染，用户体验好。</p><p><strong>WebSocket</strong>：全双工通信，适合双向实时交互（如聊天室、协同编辑）。开销比SSE大，对于&quot;用户提问→AI回答&quot;这种请求-响应模式是过度设计。但适合需要中断生成的场景——用户点击&quot;停止生成&quot;时，通过WebSocket发送中断信号。</p><p><strong>长轮询</strong>：客户端发送请求，服务端hold住直到有数据或超时。每次请求建立新连接，延迟高、资源消耗大。已基本被SSE/WebSocket取代。</p><p><strong>碳管家选型建议</strong>：主要对话流使用SSE（简单、与HTTP基础设施兼容），管理后台通知使用WebSocket（需要双向推送），对于不支持SSE的旧客户端降级为长轮询。Spring Boot中SSE实现：<code>@GetMapping(produces = MediaType.TEXT_EVENT_STREAM_VALUE)</code> 返回 <code>Flux&lt;ServerSentEvent&gt;</code>。</p><h4 id="f-21-4" tabindex="-1">追问： <a class="header-anchor" href="#f-21-4" aria-label="Permalink to &quot;追问： {#f-21-4}&quot;">​</a></h4><ul><li>追问1：当碳管家需要支持&quot;用户中途点击停止生成&quot;时，SSE单向流的局限性如何弥补，是否必须引入WebSocket？ <ul><li><strong>答</strong>：不必强引入 WebSocket。可行方案： <ul><li>客户端 <code>EventSource.close()</code> 断开，服务端在 Flux 的 <code>doOnCancel</code> 中感知并中断模型生成（取消 CompletableFuture / 断开模型侧流）；</li><li>通过单独的 REST 接口下发&quot;停止&quot;指令，服务端按会话 ID 取消对应生成任务；</li><li>仅当需低延迟双向交互时再考虑 WebSocket。</li></ul></li></ul></li><li>追问2：对于不支持SSE的旧客户端降级为长轮询，如何实现服务端&quot;hold住请求&quot;而不阻塞WebFlux事件循环？ <ul><li><strong>答</strong>：基于响应式非阻塞实现：用 <code>Mono.delay</code>/<code>Sinks</code>/<code>Flux</code> 挂起请求，由数据到达事件（消息队列投递、Redis 发布订阅）触发 <code>onNext</code> 完成响应，而非 <code>Thread.sleep</code> 阻塞；超时由 <code>timeout</code> 操作符控制返回空响应，事件循环线程始终不被占用。</li></ul></li><li>追问3：在Nginx反向代理后，SSE长连接可能受到proxy_read_timeout中断，应如何配置并配合心跳保活？ <ul><li><strong>答</strong>： <ul><li>对 SSE 路径单独调大 <code>proxy_read_timeout</code>（如 3600s），并关闭 <code>proxy_buffering</code> 保证实时推送；</li><li>服务端定时发送 SSE 注释行心跳（<code>: heartbeat\\n\\n</code>）维持连接活跃；</li><li>客户端 EventSource 自动重连，配合 <code>Last-Event-ID</code> 断点续传。</li></ul></li></ul></li></ul><h3 id="q-21-5" tabindex="-1">5. DNS解析过程与CDN原理 <a class="header-anchor" href="#q-21-5" aria-label="Permalink to &quot;5. DNS解析过程与CDN原理 {#q-21-5}&quot;">​</a></h3><p><strong>DNS解析过程</strong>：</p><ol><li>浏览器缓存 → 操作系统hosts文件 → 本地DNS服务器</li><li>本地DNS向根域名服务器查询（返回顶级域服务器地址）</li><li>向顶级域服务器查询（返回权威DNS服务器地址）</li><li>向权威DNS服务器查询（返回最终IP）</li><li>本地DNS缓存结果并返回客户端</li></ol><p><strong>CDN原理</strong>：通过DNS智能解析（GSLB），根据用户IP返回最近的CDN边缘节点。边缘节点缓存静态资源，未命中时回源到源站。核心组件：全局负载均衡（DNS调度）、边缘节点（缓存）、源站。</p><p>在碳管理SaaS中，面向全国企业用户，前端静态资源（Vue/React打包文件）通过CDN加速，全国就近访问。AI助手的知识库文件（PDF/文档）也可通过CDN分发，但需注意数据合规——部分企业客户的碳排放数据敏感，不宜使用公共CDN，应搭建私有CDN或使用对象存储的私有读写。</p><h4 id="f-21-5" tabindex="-1">追问： <a class="header-anchor" href="#f-21-5" aria-label="Permalink to &quot;追问： {#f-21-5}&quot;">​</a></h4><ul><li>追问1：碳管家知识库文档通过CDN分发，但部分企业碳排放数据敏感不宜走公共CDN，如何设计&quot;公有资源加速+私有数据不走CDN&quot;的分流策略？ <ul><li><strong>答</strong>： <ul><li>按资源类型/路径路由：静态前端资源、文档模板走公共 CDN；含企业排放数据的知识库文件标记为私有，回源到私有对象存储（带鉴权签名）；</li><li>敏感内容设 <code>Cache-Control: private</code>/<code>no-store</code>，阻止公共 CDN 缓存；</li><li>私有资料经签名 URL + JWT 鉴权直连源站/私有桶，敏感数据不出内网。</li></ul></li></ul></li><li>追问2：当CDN边缘节点回源超时或返回错误时，如何快速判断是DNS调度问题、缓存命中问题还是源站问题？ <ul><li><strong>答</strong>： <ul><li>看响应头 <code>X-Cache: HIT/MISS</code>，MISS 且慢多为回源；</li><li>DNS 调度问题：<code>dig</code>/<code>curl -v</code> 看解析到的边缘节点地域是否异常；</li><li>回源超时查源站响应时间与 CDN 回源超时配置；源站错误查源站日志与 5xx（通常透传或返回特定错误码）。</li></ul></li></ul></li></ul><h3 id="q-21-6" tabindex="-1">6. 反向代理与正向代理 <a class="header-anchor" href="#q-21-6" aria-label="Permalink to &quot;6. 反向代理与正向代理 {#q-21-6}&quot;">​</a></h3><p><strong>正向代理</strong>：代理客户端，客户端知道目标服务器但通过代理访问。典型场景：VPN翻墙、企业内网代理上网。客户端需配置代理地址。</p><p><strong>反向代理</strong>：代理服务端，客户端不知道真实服务器。典型场景：Nginx在服务前做负载均衡、SSL卸载、静态资源缓存。客户端只与反向代理通信。</p><p>在AI服务架构中，Nginx作为反向代理部署在AI网关前：(1) 负载均衡：将AI请求分发到多个Spring Boot实例；(2) 限流：使用limit_req限制API调用频率防止Token滥用；(3) SSL终端：集中在Nginx处理HTTPS，后端服务使用HTTP降低开销；(4) 缓存：对相同问题的回答做短期缓存减少模型调用。反向代理层是AI服务质量保障的第一道防线。</p><h4 id="f-21-6" tabindex="-1">追问： <a class="header-anchor" href="#f-21-6" aria-label="Permalink to &quot;追问： {#f-21-6}&quot;">​</a></h4><ul><li>追问1：碳管家在Nginx层对相同问题回答做短期缓存以减少模型调用，但用户问的是&quot;我的排放数据&quot;这类个性化内容，如何避免缓存串号？ <ul><li><strong>答</strong>： <ul><li>缓存 key 必须包含用户/企业维度（如 <code>userId</code>/<code>tenantId</code>），而非仅基于问题文本；</li><li>个性化内容直接跳过缓存或按租户隔离命名空间；</li><li>涉及私有数据的请求设 <code>Cache-Control: private</code> 或不缓存，仅对完全公共内容做缓存。</li></ul></li></ul></li><li>追问2：Nginx做SSL终端后后端用HTTP，若内网被横向渗透是否会泄露明文流量，是否应在后端也启用mTLS？ <ul><li><strong>答</strong>： <ul><li>内网被横向渗透时，Nginx 后的 HTTP 明文确实可被嗅探，零信任架构下建议后端也启用 mTLS；</li><li>折中：用 VPC/安全组严格隔离私有子网，仅在跨信任边界（多租户混部、不可信通道）启用后端 mTLS；</li><li>可用服务网格（如 Istio）透明注入 mTLS，对应用无侵入。</li></ul></li></ul></li><li>追问3：limit_req限流是按IP还是按JWT用户维度，如何在高并发下既防Token滥用又不影响同一企业的多员工正常使用？ <ul><li><strong>答</strong>： <ul><li>优先按 JWT 中的 <code>tenantId</code>/<code>userId</code> 维度限流，避免同企业多员工被单 IP 误伤；</li><li>Nginx 通过 njs/lua 解析 Authorization 头取用户标识作为限流 key；</li><li>双层限流：全局按 IP 防单点洪水，业务按用户/租户防配额耗尽，配合租户级 QPS/Token 预算，超限返回 429。</li></ul></li></ul></li></ul><h3 id="q-21-7" tabindex="-1">7. Cookie/Session/Token/JWT的区别与安全性 <a class="header-anchor" href="#q-21-7" aria-label="Permalink to &quot;7. Cookie/Session/Token/JWT的区别与安全性 {#q-21-7}&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方案</th><th>存储位置</th><th>状态</th><th>特点</th><th>安全风险</th></tr></thead><tbody><tr><td>Cookie</td><td>浏览器</td><td>有状态</td><td>自动携带，4KB限制</td><td>CSRF、XSS窃取</td></tr><tr><td>Session</td><td>服务端(Cookie存SessionID)</td><td>有状态</td><td>安全，服务端控制</td><td>分布式需共享存储</td></tr><tr><td>Token</td><td>客户端</td><td>无状态</td><td>自定义Payload</td><td>需HTTPS传输</td></tr><tr><td>JWT</td><td>客户端</td><td>无状态</td><td>自包含，可验证签名</td><td>无法主动撤销</td></tr></tbody></table><p><strong>JWT结构</strong>：Header.Payload.Signature，Base64编码。Payload不要存敏感信息（仅Base64编码非加密）。Access Token短期有效（15分钟），搭配Refresh Token（7天）实现自动续期。</p><p><strong>碳管家AI助手的认证方案</strong>：用户登录后下发JWT，前端每次请求在Authorization头携带。AI对话接口需要JWT验证用户身份和权限（不同企业用户只能查自己的碳数据）。JWT Payload中包含用户ID、企业ID、角色。由于JWT无法主动撤销，使用Redis黑名单实现强制登出。WebSocket连接建立时通过URL参数传递Token，服务端在握手阶段验证。</p><h4 id="f-21-7" tabindex="-1">追问： <a class="header-anchor" href="#f-21-7" aria-label="Permalink to &quot;追问： {#f-21-7}&quot;">​</a></h4><ul><li>追问1：JWT无法主动撤销，碳管家用Redis黑名单实现强制登出，黑名单膨胀后如何兼顾性能与安全性？ <ul><li><strong>答</strong>： <ul><li>黑名单只存&quot;已注销但未过期的 Access Token&quot;的 jti，TTL 设为与 Token 剩余有效期一致，自动过期不再膨胀；</li><li>用 Redis 集合 + 过期时间，查询走 O(1) 内存查找；</li><li>缩短 Access Token 有效期（如 15 分钟）减小窗口；</li><li>强登出也可改签 Secret/版本号使旧 Token 集体失效，减少逐条记录。</li></ul></li></ul></li><li>追问2：WebSocket握手通过URL参数传Token，相比Authorization头有哪些额外的安全风险应如何防护？ <ul><li><strong>答</strong>： <ul><li>Token 出现在 URL 会被写入访问日志、代理日志、浏览器历史，存在泄露风险；</li><li>防护：使用短期有效的专用 ws token（一次性票据），传输后立即作废；</li><li>全程 HTTPS 加密防嗅探；</li><li>握手校验后立即清除日志中的敏感参数，或改用 <code>Sec-WebSocket-Protocol</code> 头传 token 并禁止记录。</li></ul></li></ul></li></ul><h3 id="q-21-8" tabindex="-1">8. 跨域问题（CORS）及解决方案 <a class="header-anchor" href="#q-21-8" aria-label="Permalink to &quot;8. 跨域问题（CORS）及解决方案 {#q-21-8}&quot;">​</a></h3><p><strong>同源策略</strong>：浏览器安全机制，限制不同源的文档或脚本交互。同源 = 协议+域名+端口完全相同。</p><p><strong>CORS（跨域资源共享）</strong>：服务端通过HTTP头部告知浏览器允许跨域。关键头部：</p><ul><li><code>Access-Control-Allow-Origin</code>：允许的源</li><li><code>Access-Control-Allow-Methods</code>：允许的HTTP方法</li><li><code>Access-Control-Allow-Headers</code>：允许的请求头</li><li><code>Access-Control-Allow-Credentials</code>：是否允许携带Cookie</li><li><code>Access-Control-Max-Age</code>：预检请求缓存时间</li></ul><p><strong>简单请求与预检请求</strong>：简单请求（GET/HEAD/POST且Content-Type为表单类型）直接发送跨域请求；非简单请求（如Content-Type: application/json）先发OPTIONS预检请求，服务端确认允许后才发实际请求。</p><p><strong>Spring Boot CORS配置</strong>：全局配置通过<code>WebMvcConfigurer.addCorsMappings()</code>，或<code>@CrossOrigin</code>注解。碳管家场景：前端部署在<code>https://carbon.example.com</code>，后端API在<code>https://api.carbon.example.com</code>（子域名也算跨域），需配置CORS允许前端域名。也使用Nginx反向代理统一域名避免跨域。</p><h4 id="f-21-8" tabindex="-1">追问： <a class="header-anchor" href="#f-21-8" aria-label="Permalink to &quot;追问： {#f-21-8}&quot;">​</a></h4><ul><li>追问1：碳管家前端与API是不同子域名算跨域，若用Nginx统一域名规避CORS，具体应如何配置路由与路径转发？ <ul><li><strong>答</strong>： <ul><li>前端与 API 配到同一域名（如 <code>carbon.example.com</code>），前端 <code>/</code>、后端 <code>/api</code> 由 Nginx 按 <code>location</code> 反代到不同 upstream；</li><li>例：<code>location /api/ { proxy_pass http://backend; }</code>，其余 <code>location / { root 前端; }</code>；</li><li>浏览器视为同源，无需 CORS 头；仅对确需跨域的第三方保留显式 CORS。</li></ul></li></ul></li><li>追问2：Access-Control-Allow-Origin设为通配符*时会与携带Cookie的凭证请求冲突，Spring Boot中应如何正确配置允许的源？ <ul><li><strong>答</strong>： <ul><li><code>*</code> 不能与 <code>Allow-Credentials: true</code> 同用，浏览器会拒绝；</li><li>应回显具体来源：<code>allowCredentials(true)</code> + <code>allowedOrigins(具体域名列表)</code>，动态读取 <code>Origin</code> 请求头并白名单校验后回写；</li><li>明确列出可信前端域名，兼顾凭证与跨域。</li></ul></li></ul></li></ul><h3 id="q-21-9" tabindex="-1">9. 网络攻击（XSS/CSRF/SQL注入/DDoS）防护 <a class="header-anchor" href="#q-21-9" aria-label="Permalink to &quot;9. 网络攻击（XSS/CSRF/SQL注入/DDoS）防护 {#q-21-9}&quot;">​</a></h3><p><strong>XSS（跨站脚本）</strong>：</p><ul><li>存储型：攻击脚本存入数据库，用户浏览时执行</li><li>反射型：脚本在URL参数中，服务端反射到页面</li><li>DOM型：纯前端漏洞</li><li>防护：输出编码、CSP（Content Security Policy）、HttpOnly Cookie</li></ul><p><strong>CSRF（跨站请求伪造）</strong>：利用用户已登录状态发起恶意请求。防护：CSRF Token（Spring Security内置）、SameSite Cookie、Referer/Origin验证。</p><p><strong>SQL注入</strong>：攻击者拼接恶意SQL语句。防护：使用PreparedStatement（参数化查询）、ORM框架、输入校验。碳管家中查询碳排放数据时，绝对禁止拼接SQL，参数化查询是底线。</p><p><strong>DDoS</strong>：分布式拒绝服务。SYN Flood攻击TCP握手环节。防护：CDN/高防IP、限流、黑名单、WAF（Web应用防火墙）。</p><p><strong>AI服务特有攻击</strong>：Prompt注入（见第二十五章）、模型盗取（大量请求探测模型行为）、数据投毒（恶意数据污染知识库）。碳管家在Nginx层配置rate_limit限制单用户QPS，在应用层监控异常请求模式。</p><h4 id="f-21-9" tabindex="-1">追问： <a class="header-anchor" href="#f-21-9" aria-label="Permalink to &quot;追问： {#f-21-9}&quot;">​</a></h4><ul><li>追问1：碳管家等知识库RAG系统特有的Prompt注入攻击，与传统的XSS防护思路有何不同，应在哪一层拦截？ <ul><li><strong>答</strong>： <ul><li>XSS 是向浏览器注入脚本，防护在输出编码/CSP；Prompt 注入是向 LLM 注入指令，执行环境是模型而非浏览器，传统 XSS 防护无效；</li><li>应在应用层/提示层拦截：输入侧对用户输入做敏感指令检测与隔离（明确分隔 system/用户内容），输出侧过滤违规内容；</li><li>结合 RAG 上下文权限校验防越权读取，需专门的 Prompt 防火墙/护栏而非仅 WAF。</li></ul></li></ul></li><li>追问2：面对针对大模型推理服务的DDoS或模型盗取（大量探测请求），Nginx限流与应用层监控应如何配合？ <ul><li><strong>答</strong>： <ul><li>Nginx 层按租户/IP 做粗粒度 QPS 限流与连接数限制，拦掉明显洪水；</li><li>应用层监控异常模式：单用户高频相似请求、探测式输入输出对、Token 消耗异常突增，触发更细粒度限流或临时封禁；</li><li>对推理结果做差异化/限速返回提高模型盗取成本；</li><li>分层：Nginx 挡量、应用层挡&quot;聪明的&quot;探测。</li></ul></li></ul></li></ul><h3 id="q-21-10" tabindex="-1">10. TCP拥塞控制算法 <a class="header-anchor" href="#q-21-10" aria-label="Permalink to &quot;10. TCP拥塞控制算法 {#q-21-10}&quot;">​</a></h3><p><strong>核心算法</strong>：</p><ul><li><strong>慢启动</strong>：初始cwnd小，每收到ACK指数增长（cwnd*=2），直到ssthresh阈值</li><li><strong>拥塞避免</strong>：超过ssthresh后线性增长（cwnd+=1每RTT）</li><li><strong>快重传</strong>：收到3个重复ACK立即重传（不等超时）</li><li><strong>快恢复</strong>：快重传后不进入慢启动，而将ssthresh减半后进入拥塞避免</li></ul><p><strong>经典算法演进</strong>：Tahoe → Reno → NewReno → CUBIC（Linux默认） → BBR（Google提出，基于带宽探测而非丢包）。CUBIC适合高带宽长距离网络，BBR在有一定丢包率的网络上表现更好。</p><p>对AI服务的影响：内网微服务间TCP通信通常不受拥塞控制限制（低延迟、低丢包），但大模型推理结果在公网传输时，拥塞控制影响用户体验。流式输出（SSE）结合BBR算法能在弱网环境获得更流畅的推送效果。</p><h4 id="f-21-10" tabindex="-1">追问： <a class="header-anchor" href="#f-21-10" aria-label="Permalink to &quot;追问： {#f-21-10}&quot;">​</a></h4><ul><li>追问1：碳管家SSE流式输出在公网弱网环境，选用BBR相比CUBIC能带来什么可量化的体验提升，如何验证？ <ul><li><strong>答</strong>： <ul><li>BBR 基于带宽/RTT 探测，弱网/有丢包时吞吐高于 CUBIC（CUBIC 遇丢包误判拥塞而降窗），可提升流式稳定性；</li><li>验证：在设丢包率（如 1-3%）链路上对比两者 SSE 完成时间、重传率、吞吐；用 <code>ss -ti</code> 看 cwnd/bbr 状态；</li><li>内核开启 <code>tcp_bbr</code> 并设为默认，灰度对比指标。</li></ul></li></ul></li><li>追问2：内网微服务间通信如果用到了拥塞控制，什么场景下反而会成为降低吞吐的瓶颈？ <ul><li><strong>答</strong>： <ul><li>内网低延迟低丢包本不应触发，但若出现微突发/缓冲区膨胀（bufferbloat）致 RTT 抖动，CUBIC 仍会降速；</li><li>大块传输（模型权重、批量向量）走 TCP 可能被保守窗限流，反不如 RDMA/用户态协议；</li><li>解决：调大初始 cwnd、改用 BBR，或走专用高速网络（如 InfiniBand），避免在瓶颈交换机处排队。</li></ul></li></ul></li></ul><h3 id="q-21-11" tabindex="-1">11. OSI七层模型与TCP/IP四层模型 <a class="header-anchor" href="#q-21-11" aria-label="Permalink to &quot;11. OSI七层模型与TCP/IP四层模型 {#q-21-11}&quot;">​</a></h3><table tabindex="0"><thead><tr><th>OSI层</th><th>TCP/IP层</th><th>协议/设备</th><th>功能</th></tr></thead><tbody><tr><td>应用层</td><td>应用层</td><td>HTTP/DNS/SSH/SMTP</td><td>应用程序接口</td></tr><tr><td>表示层</td><td>应用层</td><td>TLS/SSL, 编码</td><td>数据格式转换、加密</td></tr><tr><td>会话层</td><td>应用层</td><td>RPC, Socket</td><td>会话管理</td></tr><tr><td>传输层</td><td>传输层</td><td>TCP/UDP</td><td>端到端可靠传输</td></tr><tr><td>网络层</td><td>网络层</td><td>IP/ICMP, 路由器</td><td>寻址与路由</td></tr><tr><td>数据链路层</td><td>网络接口层</td><td>ARP, 交换机</td><td>帧传输、MAC寻址</td></tr><tr><td>物理层</td><td>网络接口层</td><td>网线/光纤</td><td>比特流传输</td></tr></tbody></table><p>实际开发中，问题排查遵循&quot;自下而上&quot;原则：先检查物理连接 → IP可达（ping） → 端口可达（telnet） → 服务进程（ps） → 应用日志。碳管家部署遇到用户无法访问问题时，按此顺序逐步排查。</p><h4 id="f-21-11" tabindex="-1">追问： <a class="header-anchor" href="#f-21-11" aria-label="Permalink to &quot;追问： {#f-21-11}&quot;">​</a></h4><ul><li>追问1：碳管家Kubernetes集群中Pod跨节点通信不通，如何用&quot;自下而上&quot;的排查思路结合CNI网络模型定位？ <ul><li><strong>答</strong>： <ul><li>自下而上：先 <code>ping</code> 节点 IP（网络层）→ 查 Pod IP 路由（CNI 分配网段）→ kube-proxy/iptables 规则 → CNI 插件（Calico/Flannel）Pod 状态；</li><li>常见：CNI 子网重叠、节点安全组未放行隧道端口（如 VXLAN 8472/UDP）、路由表缺失；</li><li><code>kubectl get pods -o wide</code> 确认 IP 分配，<code>tcpdump</code> 在节点抓隧道口流量定位丢包点。</li></ul></li></ul></li><li>追问2：TLS在OSI中表示层、在TCP/IP中归应用层，这种分层差异对理解gRPC over HTTP/2有何实际帮助？ <ul><li><strong>答</strong>： <ul><li>理解 TLS 处于&quot;表示/安全层&quot;而非传输层，有助于区分：HTTP/2 负责多路复用/帧，TLS 负责加密，两者正交；</li><li>gRPC 建立在 HTTP/2+TLS 上，清楚分层后能正确配置 ALPN（h2 协商）、mTLS 与应用逻辑；</li><li>排查时分别定位：握手失败看 TLS 层，流阻塞看 HTTP/2 层，避免混淆。</li></ul></li></ul></li></ul><h3 id="q-21-12" tabindex="-1">12. RESTful API设计原则 <a class="header-anchor" href="#q-21-12" aria-label="Permalink to &quot;12. RESTful API设计原则 {#q-21-12}&quot;">​</a></h3><p><strong>核心原则</strong>：</p><ol><li><strong>资源导向</strong>：URL表示资源而非操作，如<code>/api/carbon-reports/{id}</code> 而非 <code>/api/getCarbonReport</code></li><li><strong>HTTP方法语义</strong>：GET查询、POST创建、PUT全量更新、PATCH部分更新、DELETE删除</li><li><strong>状态码准确</strong>：200成功、201创建成功、400参数错误、401未认证、403无权限、404不存在、500服务器错误</li><li><strong>无状态</strong>：每个请求包含所有必要信息，服务端不保存客户端状态</li><li><strong>版本控制</strong>：通过URL路径（/api/v1/）或Header标识版本</li><li><strong>分页与过滤</strong>：<code>?page=1&amp;size=20&amp;sort=emissionDate,desc&amp;companyId=123</code></li></ol><p><strong>碳管家API设计示例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET    /api/v1/carbon-reports          # 查询碳排放报告列表（分页）</span></span>
<span class="line"><span>GET    /api/v1/carbon-reports/{id}     # 查询单个报告</span></span>
<span class="line"><span>POST   /api/v1/carbon-reports          # 创建报告</span></span>
<span class="line"><span>PUT    /api/v1/carbon-reports/{id}     # 更新报告</span></span>
<span class="line"><span>DELETE /api/v1/carbon-reports/{id}     # 删除报告</span></span>
<span class="line"><span>POST   /api/v1/ai/chat                 # AI对话（流式返回）</span></span>
<span class="line"><span>POST   /api/v1/ai/chat/feedback        # 对话反馈</span></span></code></pre></div><p>响应统一包装为<code>{ code, message, data, timestamp }</code>结构，便于前端统一处理。HATEOAS在简单CRUD场景下过度设计不推荐。</p><h4 id="f-21-12" tabindex="-1">追问： <a class="header-anchor" href="#f-21-12" aria-label="Permalink to &quot;追问： {#f-21-12}&quot;">​</a></h4><ul><li>追问1：碳管家AI对话是流式返回，用POST /api/v1/ai/chat但标准REST对GET才缓存，流式接口应如何设计幂等与重试？ <ul><li><strong>答</strong>： <ul><li>幂等：客户端携带幂等键（Idempotency-Key/会话 ID），服务端去重，重复提交返回同一结果流；</li><li>重试：SSE 中断后客户端用 <code>Last-Event-ID</code> 或 offset 续传，服务端据游标重放后续 token；</li><li>生成类请求弱幂等，可用会话级状态记录已生成内容，避免重复计费/生成。</li></ul></li></ul></li><li>追问2：统一包装{code,message,data,timestamp}后，前端如何区分业务错误码与HTTP状态码，二者职责如何划分？ <ul><li><strong>答</strong>： <ul><li>HTTP 状态码表达&quot;传输/协议层&quot;结果（成功、鉴权失败、限流、服务异常）；</li><li><code>code</code> 表达&quot;业务语义&quot;（碳数据不存在、配额不足、模型超时），供前端分支处理；</li><li>前端先判 HTTP 状态再读业务 code；避免把业务错误用 200 掩盖（反模式）。</li></ul></li></ul></li><li>追问3：若后续需要HATEOAS或GraphQL，当前以资源为中心的REST设计需要预留哪些扩展点？ <ul><li><strong>答</strong>： <ul><li>资源 URL 保持稳定、语义化，便于 GraphQL 在同一资源上做字段裁剪；</li><li>统一响应中预留 <code>_links</code>（HATEOAS）或 <code>cursor</code>/分页元数据，渐进增强；</li><li>保持资源边界清晰（聚合根），GraphQL 可在此之上建 schema；</li><li>错误/分页/过滤参数保持规范，方便网关层协议转换。</li></ul></li></ul></li></ul><h3 id="q-21-13" tabindex="-1">13. gRPC原理与使用场景 <a class="header-anchor" href="#q-21-13" aria-label="Permalink to &quot;13. gRPC原理与使用场景 {#q-21-13}&quot;">​</a></h3><p><strong>gRPC</strong>：Google开源的高性能RPC框架，使用Protocol Buffers（protobuf）作为IDL和序列化协议，基于HTTP/2传输。</p><p><strong>核心优势</strong>：(1) Protobuf二进制序列化比JSON体积小3-10倍、速度快；(2) HTTP/2多路复用减少连接数；(3) 强类型契约，自动生成客户端代码；(4) 支持四种通信模式：一元RPC、服务端流、客户端流、双向流。</p><p><strong>适用场景</strong>：微服务间高性能通信、移动端与后端通信（省流量）、实时数据推送。不适用于需要浏览器直接调用的公开API（浏览器对gRPC支持有限，需gRPC-Web代理）。</p><p><strong>碳管家微服务通信选型</strong>：AI推理服务与业务服务间模型调用使用gRPC（大数据量、低延迟要求）；前端到API网关使用RESTful（浏览器兼容）；消息通知使用消息队列异步解耦。Spring Boot集成gRPC通过grpc-spring-boot-starter。</p><h4 id="f-21-13" tabindex="-1">追问： <a class="header-anchor" href="#f-21-13" aria-label="Permalink to &quot;追问： {#f-21-13}&quot;">​</a></h4><ul><li>追问1：碳管家AI推理服务与业务服务间用gRPC，若推理服务用Python而业务用Java，protobuf契约应如何管理与版本演进？ <ul><li><strong>答</strong>： <ul><li><code>.proto</code> 文件作为单一事实来源，独立仓库管理并通过版本标签（如 v1.2.0）发布；</li><li>双方各自用 protoc/插件生成 Java 与 Python 代码，CI 中校验契约兼容（禁止删字段、改字段号）；</li><li>用 <code>reserved</code> 保留废弃字段号，配合 buf 做 lint/breaking-change 检测与版本演进。</li></ul></li></ul></li><li>追问2：gRPC基于HTTP/2多路复用，当单个流式调用长时间占用连接时，是否会引发其他调用的队头阻塞？ <ul><li><strong>答</strong>： <ul><li>HTTP/2 多路复用下不同流独立帧交错，单个长流不会阻塞其他流的帧传输（应用层无队头阻塞）；</li><li>但同一条 TCP 连接上若丢包，TCP 层重传仍会让所有流等待（TCP 队头阻塞），与流无关；</li><li>缓解：控制单连接流数，或对关键调用用独立连接/HTTP/3(QUIC) 隔离。</li></ul></li></ul></li><li>追问3：浏览器无法直接调用gRPC，碳管家前端到API网关用REST，网关到推理服务用gRPC，这种协议转换的边界放在哪层最合理？ <ul><li><strong>答</strong>： <ul><li>转换边界放在 API 网关层最合理：网关对外暴露 REST/JSON（浏览器友好），对内用 gRPC 调推理服务；</li><li>网关负责协议翻译、鉴权、限流，后端微服务专注业务/推理；</li><li>避免把转换逻辑散落到各业务服务，可用 Spring Cloud Gateway 配 grpc 客户端做转码，保持单一网关入口。</li></ul></li></ul></li></ul><h3 id="q-21-14" tabindex="-1">14. 网络性能优化（keep-alive、连接池、压缩） <a class="header-anchor" href="#q-21-14" aria-label="Permalink to &quot;14. 网络性能优化（keep-alive、连接池、压缩） {#q-21-14}&quot;">​</a></h3><p><strong>HTTP Keep-Alive</strong>：复用TCP连接发送多个HTTP请求，避免频繁握手。HTTP/1.1默认开启，通过<code>Connection: keep-alive</code>和<code>Keep-Alive: timeout=5, max=1000</code>控制。AI流式输出场景必须用长连接。</p><p><strong>连接池</strong>：客户端维护一组预建立的连接，请求时从池中获取用完归还。数据库连接池（HikariCP）、HttpClient连接池、Redis连接池都是此模式。关键参数：最大连接数、最小空闲连接、连接超时、空闲超时。碳管家使用HikariCP管理数据库连接，默认10个连接应对常规负载。</p><p><strong>数据压缩</strong>：HTTP内容压缩（gzip/brotli）可减少传输量50-80%。Spring Boot配置<code>server.compression.enabled=true</code>。AI响应数据中，JSON格式的碳排放数据压缩效果显著；已压缩的静态资源（图片）不重复压缩。</p><p><strong>其他优化</strong>：TCP_NODELAY禁用Nagle算法减少延迟（实时通信场景）；合理设置缓冲区大小；DNS预解析；使用CDN缓存静态资源。</p><h4 id="f-21-14" tabindex="-1">追问： <a class="header-anchor" href="#f-21-14" aria-label="Permalink to &quot;追问： {#f-21-14}&quot;">​</a></h4><ul><li>追问1：碳管家使用HikariCP默认10个连接，若RAG检索+大模型推理并发上升，如何根据慢查询与等待队列调优连接数？ <ul><li><strong>答</strong>： <ul><li>监控连接等待（<code>hikari.pool</code> 等待队列、获取连接耗时）与慢查询，若频繁等待则增大 <code>maximumPoolSize</code>；</li><li>经验公式：<code>连接数 ≈ 核心数*2 + IO 等待数</code>，但需结合 DB 承载；</li><li>将 DB 操作与耗时推理解耦（异步/消息队列），缩短连接占用；</li><li>设置合理 <code>connectionTimeout</code>/<code>idleTimeout</code> 防泄漏。</li></ul></li></ul></li><li>追问2：开启gzip/brotli压缩对大模型返回的JSON碳排放数据有效，但SSE逐token流式输出能否压缩，压缩会带来什么副作用？ <ul><li><strong>答</strong>： <ul><li>SSE 逐 token 流式可开启 gzip/brotli，但压缩需累积一定数据才出窗口，会引入&quot;压缩缓冲延迟&quot;，破坏实时打字机效果；</li><li>故流式场景通常关闭对 event-stream 的压缩或降低压缩级别；</li><li>已生成的完整大块 JSON（非流式）再压缩收益高，Nginx 可按 Content-Type 对 SSE 关压缩。</li></ul></li></ul></li><li>追问3：TCP_NODELAY禁用Nagle算法降低延迟，但在高并发小包场景是否可能引发更多小报文从而影响吞吐？ <ul><li><strong>答</strong>： <ul><li>禁用 Nagle 后每个小包立即发送，高频小包（逐 token）降低延迟但增加报文数与中断开销，可能降吞吐；</li><li>权衡：实时性场景（SSE token）优先延迟开 TCP_NODELAY；批量数据可合并发送；</li><li>应用层做小批量聚合（攒几个 token 再发）兼顾延迟与报文数，或用 <code>TCP_CORK</code> 临时聚合后 flush。</li></ul></li></ul></li></ul><h3 id="q-21-15" tabindex="-1">15. Wireshark抓包分析实战 <a class="header-anchor" href="#q-21-15" aria-label="Permalink to &quot;15. Wireshark抓包分析实战 {#q-21-15}&quot;">​</a></h3><p><strong>基本使用</strong>：选择网卡 → 设置过滤器 → 开始抓包 → 分析数据包。常用过滤器：<code>tcp.port==8080</code>（过滤端口）、<code>http.request.method==POST</code>（过滤HTTP方法）、<code>ip.addr==192.168.1.100</code>（过滤IP）。</p><p><strong>TCP三次握手分析</strong>：筛选<code>tcp.stream eq 0</code>查看单个TCP流，观察SYN → SYN+ACK → ACK的Flags字段和Seq/Ack序号。</p><p><strong>HTTPS流量分析</strong>：需要导入服务器私钥或在浏览器导出SSLKEYLOGFILE，Wireshark才能解密。生产环境排查SSL握手失败时很有用。</p><p><strong>AI服务调试实战</strong>：</p><ol><li>用过滤器抓取AI对话请求：<code>http.host contains &quot;carbon-api&quot;</code></li><li>查看SSE流式响应：<code>http.response.code == 200 &amp;&amp; http.content_type contains &quot;event-stream&quot;</code></li><li>分析响应延迟：统计请求-响应时间差值</li><li>排查丢包重传：<code>tcp.analysis.retransmission</code></li></ol><p>Wireshark是网络问题&quot;最后一公里&quot;的排查工具，当应用日志无法定位问题时，抓包能揭示TCP层面、TLS层面的底层原因。</p><h4 id="f-21-15" tabindex="-1">追问： <a class="header-anchor" href="#f-21-15" aria-label="Permalink to &quot;追问： {#f-21-15}&quot;">​</a></h4><ul><li>追问1：碳管家生产环境用HTTPS，Wireshark无私钥无法解密SSE流量，如何在合规前提下用SSLKEYLOGFILE排查握手失败？ <ul><li><strong>答</strong>： <ul><li>在受控调试环境（而非生产全量）设 <code>SSLKEYLOGFILE</code> 环境变量，让 JVM/客户端导出会话密钥到指定文件，Wireshark 引用该文件解密；</li><li>严格限制该文件访问权限、用完即删，避免密钥泄露合规风险；</li><li>仅对特定会话/时段开启，不长期开启；</li><li>或临时挂自签证书导出私钥在隔离环境抓包，生产用 mTLS 日志+应用层追踪替代。</li></ul></li></ul></li><li>追问2：用tcp.analysis.retransmission发现AI响应丢包重传，应如何区分是公网链路问题还是Nginx代理缓冲区配置问题？ <ul><li><strong>答</strong>： <ul><li>看重传分布：跨公网 RTT 大且分散重传→链路问题；集中在 Nginx 与后端间且伴随 <code>proxy_buffering</code> 满/超时→代理配置问题；</li><li>查 Nginx <code>proxy_buffer_size</code>/<code>proxy_buffers</code> 是否过小导致后端快、前端慢时缓冲溢出；</li><li>在 Nginx 前后分别 <code>tcpdump</code> 比对延迟与重传位置；</li><li>调 <code>proxy_buffering off</code>+合适 <code>proxy_read_timeout</code> 验证是否消失。</li></ul></li></ul></li></ul><h3 id="q-21-16" tabindex="-1">16. HTTP状态码详解与应用 <a class="header-anchor" href="#q-21-16" aria-label="Permalink to &quot;16. HTTP状态码详解与应用 {#q-21-16}&quot;">​</a></h3><p><strong>2xx 成功</strong>：200 OK（标准成功）、201 Created（资源创建）、204 No Content（删除成功无返回体）。AI服务中，流式输出返回200并持续推送SSE事件。</p><p><strong>3xx 重定向</strong>：301永久重定向（SEO权重转移）、302临时重定向、304 Not Modified（缓存未修改）。碳管家使用301将HTTP重定向到HTTPS。</p><p><strong>4xx 客户端错误</strong>：400 Bad Request（参数校验失败）、401 Unauthorized（未认证→跳转登录）、403 Forbidden（无权限）、404 Not Found（资源不存在）、429 Too Many Requests（限流触发）。AI服务中429表示Token配额耗尽或QPS超限，前端展示&quot;请求过于频繁，请稍后再试&quot;。</p><p><strong>5xx 服务端错误</strong>：500 Internal Server Error（通用异常）、502 Bad Gateway（上游服务异常，如Python模型服务挂了）、503 Service Unavailable（服务临时不可用）、504 Gateway Timeout（上游超时）。AI推理超60秒返回504时，应在Nginx配置合理的proxy_read_timeout（流式输出需更长时间）。</p><p>正确处理各状态码是API成熟度的体现。统一异常处理器捕获异常并映射到合适的状态码。</p><h4 id="f-21-16" tabindex="-1">追问： <a class="header-anchor" href="#f-21-16" aria-label="Permalink to &quot;追问： {#f-21-16}&quot;">​</a></h4><ul><li>追问1：碳管家AI推理超60秒返回504，但流式SSE可能持续更久，Nginx proxy_read_timeout应如何配置才既不误杀又不拖垮连接？ <ul><li><strong>答</strong>： <ul><li>SSE 流式连接设较长或禁用读取超时（如 <code>proxy_read_timeout 3600s</code> 或按业务上限），避免中途无数据被切断；</li><li>配合上游心跳（注释行）证明连接存活，否则真僵死连接也占资源；</li><li>非流式普通接口保持较短超时（如 60s），按 <code>location</code> 差异化配置；</li><li>应用层设生成总上限防资源耗尽。</li></ul></li></ul></li><li>追问2：429触发限流时前端&quot;请稍后再试&quot;，如何在响应头用Retry-After告知客户端合理重试间隔而非盲目轮询？ <ul><li><strong>答</strong>： <ul><li>限流返回 429 时，响应头带 <code>Retry-After: &lt;秒&gt;</code> 或 HTTP 日期，告知何后可重试；</li><li>配合 <code>X-RateLimit-Limit</code>/<code>Remaining</code>/<code>Reset</code> 让前端显示倒计时；</li><li>前端据 Retry-After 做指数退避而非盲目轮询；</li><li>对 Token 配额型限流，重置时间对齐配额周期。</li></ul></li></ul></li></ul><h3 id="q-21-17" tabindex="-1">17. 负载均衡策略与算法 <a class="header-anchor" href="#q-21-17" aria-label="Permalink to &quot;17. 负载均衡策略与算法 {#q-21-17}&quot;">​</a></h3><p><strong>四层负载均衡（L4）</strong>：基于IP和端口（传输层），通过修改数据包目标地址实现。LVS/HAProxy四层模式。性能高但无法根据HTTP内容路由。</p><p><strong>七层负载均衡（L7）</strong>：基于HTTP头部/URL等（应用层）。Nginx/Spring Cloud Gateway。灵活但性能略低。</p><p><strong>常用算法</strong>：</p><ul><li><strong>轮询（Round Robin）</strong>：依次分配，适合无状态服务</li><li><strong>加权轮询</strong>：根据服务器性能分配不同权重</li><li><strong>最少连接（Least Connections）</strong>：分配给当前连接最少的服务器，适合长连接场景</li><li><strong>IP Hash</strong>：根据客户端IP哈希固定分配到同一服务器，解决Session问题</li><li><strong>一致性哈希</strong>：节点增减时只影响少量映射，适合缓存服务</li></ul><p><strong>碳管家负载均衡</strong>：Nginx作为L7负载均衡分发HTTP请求到多个Spring Boot实例。AI推理服务使用最少连接策略因为各请求处理时间差异大（简单问答快、复杂RAG慢）。使用Spring Cloud Gateway实现更细粒度的路由（根据请求路径路由到不同微服务）。</p><h4 id="f-21-17" tabindex="-1">追问： <a class="header-anchor" href="#f-21-17" aria-label="Permalink to &quot;追问： {#f-21-17}&quot;">​</a></h4><ul><li>追问1：碳管家AI推理服务用最少连接策略，但复杂RAG请求耗时差异极大，最少连接是否仍会导致慢请求堆积，有何改进？ <ul><li><strong>答</strong>： <ul><li>最少连接对长耗时 RAG 仍可能把请求压到慢实例，改进：用&quot;最少活跃请求+权重/预估耗时（历史 P99）&quot;加权；</li><li>对复杂 RAG 走独立队列/实例组（按请求类型路由），与简单问答隔离；</li><li>加超时与熔断，慢请求超时被快速失败而非堆积；</li><li>用异步化+背压限制并发深度。</li></ul></li></ul></li><li>追问2：若用IP Hash固定用户到某实例以解决Session问题，但JWT本身无状态，这种绑定是否反而降低扩展性？ <ul><li><strong>答</strong>： <ul><li>JWT 无状态本不需 IP Hash 绑实例，绑定反而降低水平扩展与故障转移能力（实例下线用户需重连）；</li><li>若仅为本地会话/缓存亲和，改共享存储（Redis）或一致性哈希（节点增减影响小）；</li><li>优先去状态化：会话外置、推理无本地状态，任意实例可处理；</li><li>IP Hash 在无状态后端意义不大，建议轮询/最少连接。</li></ul></li></ul></li><li>追问3：Spring Cloud Gateway按路径路由到不同微服务，当某个微服务实例全部不健康时如何实现熔断与降级而非雪崩？ <ul><li><strong>答</strong>： <ul><li>用 Spring Cloud Gateway/Resilience4j 配置熔断（Circuit Breaker），实例连续失败达阈值则熔断，快速失败不再雪崩；</li><li>降级：返回缓存回答、兜底提示或排队页，而非一直打挂后端；</li><li>配合 readiness/liveness 健康检查从 LB 摘除不健康实例；</li><li>限流+超时+舱壁隔离，防止单服务拖垮网关。</li></ul></li></ul></li></ul><h3 id="q-21-18" tabindex="-1">18. TCP粘包/拆包问题 <a class="header-anchor" href="#q-21-18" aria-label="Permalink to &quot;18. TCP粘包/拆包问题 {#q-21-18}&quot;">​</a></h3><p><strong>问题原因</strong>：TCP是流式协议，没有边界概念。发送方多次小数据可能被合并（Nagle算法），接收方一次读取可能包含多个包的数据（粘包），或一个包被分多次接收（拆包）。</p><p><strong>解决方案</strong>：</p><ol><li><strong>固定长度</strong>：每个消息固定字节数，不足补位——效率低</li><li><strong>分隔符</strong>：用特殊字符（如<code>\\n</code>）分隔消息，适合文本协议</li><li><strong>长度字段</strong>：消息头中声明Body长度——最常用，Netty的LengthFieldBasedFrameDecoder即此方案</li><li><strong>自描述协议</strong>：使用Protobuf/HTTP这类带完整帧格式的协议</li></ol><p><strong>碳管家AI服务中的处理</strong>：Spring Boot WebFlux底层基于Netty，已处理HTTP协议的拆包粘包。如果自建TCP通信（如与C++推理引擎通信），使用Netty的LineBasedFrameDecoder或自定义解码器处理。gRPC使用HTTP/2帧格式天然解决此问题。</p><h4 id="f-21-18" tabindex="-1">追问： <a class="header-anchor" href="#f-21-18" aria-label="Permalink to &quot;追问： {#f-21-18}&quot;">​</a></h4><ul><li>追问1：碳管家若自建TCP与C++推理引擎通信，除Netty的LengthFieldBasedFrameDecoder外，如何设计一个可向后兼容的升级协议头？ <ul><li><strong>答</strong>： <ul><li>协议头固定预留版本字段（如 1 字节 magic + 1 字节 version），解析时按 version 分支；</li><li>新版本新增字段追加在尾部并保持旧字段位置/语义不变；</li><li>用长度字段包裹，未知扩展字段可跳过（TLV 结构）；</li><li>Netty 解码器据 version 选择不同 <code>ByteToMessageDecoder</code> 实现，旧客户端仍可通信。</li></ul></li></ul></li><li>追问2：使用分隔符方案时，若业务数据本身含分隔符字节，应如何转义以避免误拆包？ <ul><li><strong>答</strong>： <ul><li>发送前对数据中的分隔符字节做转义（如 <code>\\</code> 转 <code>\\\\</code>、分隔符转 <code>\\x01</code>），接收端先反转义再拆分；</li><li>或采用&quot;长度字段+分隔符&quot;混合，优先按长度读取避免误拆；</li><li>业务层对载荷做 Base64/十六进制编码，从根本上杜绝分隔符冲突；</li><li>约定转义规则并在协议文档固化，两端一致。</li></ul></li></ul></li></ul><h3 id="q-21-19" tabindex="-1">19. ARP协议与IP/MAC地址 <a class="header-anchor" href="#q-21-19" aria-label="Permalink to &quot;19. ARP协议与IP/MAC地址 {#q-21-19}&quot;">​</a></h3><p><strong>ARP（地址解析协议）</strong>：将IP地址解析为MAC地址。主机发送ARP广播请求&quot;谁的IP是192.168.1.1？请告知MAC地址&quot;，目标主机单播回复。解析结果缓存在ARP表中（<code>arp -a</code>查看）。</p><p><strong>ARP欺骗攻击</strong>：攻击者伪造ARP响应，将网关IP映射到自己的MAC，实现中间人攻击。局域网内可窃听、篡改所有流量。</p><p><strong>IP与MAC的协作</strong>：IP地址用于跨网络路由（网络层），MAC地址用于局域网内帧传输（数据链路层）。跨网段通信时，源IP和目标IP不变，但每经过一个路由器，源MAC和目标MAC都替换为当前跳的MAC地址。理解这个分层协作有助于理解Docker网络、Kubernetes CNI等容器网络原理。</p><h4 id="f-21-19" tabindex="-1">追问： <a class="header-anchor" href="#f-21-19" aria-label="Permalink to &quot;追问： {#f-21-19}&quot;">​</a></h4><ul><li>追问1：碳管家私有子网内部服务间通信，ARP欺骗在云上VPC环境是否仍可能发生，云厂商做了哪些隔离？ <ul><li><strong>答</strong>： <ul><li>云上 VPC 是三层虚拟化网络，ARP 由云网络层代理/隔离，租户间二层不互通，传统 ARP 欺骗在跨租户场景基本不可行；</li><li>同 VPC 内同一子网仍属可信边界，云厂商通过虚拟交换机隔离；</li><li>风险更多来自主机被控后的东西向渗透，建议安全组最小开放 + 内部 mTLS；</li><li>不应依赖 ARP 安全，应做零信任。</li></ul></li></ul></li><li>追问2：理解IP不变而MAC逐跳替换后，如何解释Docker bridge网络中容器跨主机通信为何需要Overlay网络？ <ul><li><strong>答</strong>： <ul><li>单主机 Docker bridge 用虚拟网桥做二层转发，但跨主机时各主机 IP 网段在底层网络不可直接路由；</li><li>容器 IP 是 overlay 私网地址，需 Overlay 网络（VXLAN 封装）把容器二层帧封装进主机 IP 包，经底层网络送达对端主机后解封装；</li><li>即&quot;MAC 逐跳替换&quot;发生在主机间，容器 MAC 在隧道内保持不变；</li><li>K8s 的 CNI（Flannel/Calico）同理。</li></ul></li></ul></li></ul><h3 id="q-21-20" tabindex="-1">20. 网络隔离与VLAN/VPC <a class="header-anchor" href="#q-21-20" aria-label="Permalink to &quot;20. 网络隔离与VLAN/VPC {#q-21-20}&quot;">​</a></h3><p><strong>VLAN（虚拟局域网）</strong>：在二层交换机上逻辑划分广播域，不同VLAN间二层隔离。通过802.1Q标签标记帧所属VLAN。企业内按部门划分VLAN（财务/研发/运维），提升安全性和网络效率。</p><p><strong>VPC（虚拟私有云）</strong>：云上的网络隔离环境，每个VPC有独立的CIDR网段。子网划分（公有子网/私有子网）、安全组（实例级防火墙）、NACL（子网级防火墙）、NAT网关。</p><p><strong>碳管家的网络隔离实践</strong>：数据库部署在私有子网（无公网IP，仅通过跳板机访问），应用服务器在公有子网后面挂载NAT网关。AI推理服务（调用外部大模型API）通过NAT网关访问公网，内部RAG检索在私有子网完成不暴露公网。安全组仅开放必要端口（443, 22, 内部服务端口），最小化攻击面。</p><hr><h4 id="f-21-20" tabindex="-1">追问： <a class="header-anchor" href="#f-21-20" aria-label="Permalink to &quot;追问： {#f-21-20}&quot;">​</a></h4><ul><li>追问1：碳管家数据库在私有子网仅跳板机可达，运维批量管理时如何在不暴露公网前提下安全地做日常维护与日志收集？ <ul><li><strong>答</strong>： <ul><li>通过跳板机/堡垒机（有公网 IP、纳入安全组）SSH 进私有子网做维护，数据库不直连公网；</li><li>日志收集用内网 Agent（如 Filebeat）推送到内网日志服务/对象存储，或经 NAT 出口上传；</li><li>批量运维用 Ansible/运维通道走私有网络；</li><li>审计与操作录屏在堡垒机完成，满足合规又不暴露数据库端口。</li></ul></li></ul></li><li>追问2：AI推理服务经NAT网关访问外部大模型API，若需审计外发数据是否满足合规，如何在NAT出口做内容审计与防泄露？ <ul><li><strong>答</strong>： <ul><li>在 NAT 网关旁路/串联部署流量审计（DLP），对出向请求做内容检测（正则/敏感词/模型 API 调用内容）；</li><li>对调用外部大模型 API 的请求记录脱敏日志（去企业标识）供合规审计；</li><li>用 egress 防火墙白名单仅放行授权的大模型 API 域名；</li><li>敏感数据在应用层先做脱敏/匿名化再外发，减少泄露面。</li></ul></li></ul></li><li>追问3：安全组仅开放必要端口，但微服务间内部调用端口众多，如何用NACL与安全组分层最小化东西向流量的攻击面？ <ul><li><strong>答</strong>： <ul><li>安全组（实例级，有状态）默认拒绝、仅开放服务间必要端口（如 gRPC 50051、MySQL 3306 仅对应用层）；</li><li>NACL（子网级，无状态）做粗粒度隔离，如隔离数据库子网与 Web 子网不可互访；</li><li>分层：NACL 划边界、安全组精细授权，东西向默认 deny；</li><li>结合 K8s NetworkPolicy 在 Pod 级再收敛，实现零信任网络。</li></ul></li></ul></li></ul><h3 id="q-21-21" tabindex="-1">补充专题：计算机网络高频题深化（新增15题） <a class="header-anchor" href="#q-21-21" aria-label="Permalink to &quot;补充专题：计算机网络高频题深化（新增15题） {#q-21-21}&quot;">​</a></h3><h3 id="q-21-22" tabindex="-1">1. TCP 三次握手为什么是三次不是两次？SYN 泛洪怎么防？ <a class="header-anchor" href="#q-21-22" aria-label="Permalink to &quot;1. TCP 三次握手为什么是三次不是两次？SYN 泛洪怎么防？ {#q-21-22}&quot;">​</a></h3><p>两次握手无法确认客户端接收能力，且服务端过早建连浪费资源；三次互相确认收发能力。</p><ul><li>SYN 泛洪：伪造源 IP 发 SYN 占满半连接队列；防：syn cookie、调大 backlog、限流。</li><li>碳管家网关对外部连接做 SYN 限速 + cookie。</li></ul><h4 id="f-21-21" tabindex="-1">追问： <a class="header-anchor" href="#f-21-21" aria-label="Permalink to &quot;追问： {#f-21-21}&quot;">​</a></h4><ul><li>追问1：半连接队列满了，正常用户的新连接会怎样？怎么观测队列水位？ <ul><li><strong>答</strong>：新 SYN 会被直接丢弃（或回 RST），客户端表现为连接超时/重传，但服务端不回任何响应，最隐蔽也最伤业务。 <ul><li>观测：<code>netstat -s</code> 看 <code>SYNs to listened sockets ignored</code>；<code>/proc/net/netstat</code> 的 <code>ListenOverflows</code>/<code>ListenDrops</code> 计数器；<code>ss -lnt</code> 看 Recv-Q 是否顶到 backlog。</li></ul></li></ul></li><li>追问2：为什么关闭 SYN cookie 会更容易被泛洪？它真的零状态吗？ <ul><li><strong>答</strong>：关闭 cookie 时每个 SYN 都要在服务端分配半连接（request_sock），队列满即丢，攻击者只发海量 SYN 就耗尽资源。开启后服务端收到 SYN 不存状态，而是用源 IP/端口/时间戳算一个带 cookie 的序号回 SYN+ACK，第三次 ACK 来了才校验并建连，所以&quot;几乎零状态&quot;。 <ul><li>代价：cookie 会关闭部分 TCP 选项协商（如大窗口、时间戳），且加密计算有开销，并非完全免费。</li></ul></li></ul></li></ul><h3 id="q-21-23" tabindex="-1">2. TCP 四次挥手？TIME_WAIT 为什么要等 2MSL？ <a class="header-anchor" href="#q-21-23" aria-label="Permalink to &quot;2. TCP 四次挥手？TIME_WAIT 为什么要等 2MSL？ {#q-21-23}&quot;">​</a></h3><p>挥手因全双工需双向关闭，所以四次；主动关闭方最后留 TIME_WAIT 等 2MSL，确保最后的 ACK 到达且旧报文消散。</p><ul><li>高并发短连接下 TIME_WAIT 过多占端口；缓解：timewait 复用(tw_reuse)、调低 MSL、用长连接。</li><li>碳管家内部服务用长连接+连接池，减少 TIME_WAIT。</li></ul><h4 id="f-21-22" tabindex="-1">追问： <a class="header-anchor" href="#f-21-22" aria-label="Permalink to &quot;追问： {#f-21-22}&quot;">​</a></h4><ul><li>追问1：服务端主动关连接导致 TIME_WAIT 堆积在服务器，为什么比在客户端更糟？ <ul><li><strong>答</strong>：服务器常作为主动关闭方（返回响应后先 close），每个 TIME_WAIT 占一个&quot;本地端口+对端&quot;五元组，高并发下本地 ephemeral 端口被耗光。 <ul><li>后果：服务器作为客户端去调下游（DB/MQ/模型服务）时无法建新连接，影响范围是服务端整体出向能力，规模远大于单客户端，且连接数量级更高。</li></ul></li></ul></li><li>追问2：tcp_tw_reuse 和 tcp_tw_recycle 区别？recycle 为什么在 NAT 下不能用？ <ul><li><strong>答</strong>：<code>tw_reuse</code> 只复用于&quot;出向&quot;连接且要求时间戳单调递增，较安全；<code>tw_recycle</code> 对&quot;入向&quot;也回收，且依赖对端时间戳严格递增。 <ul><li>NAT 下多个内网主机共用一个公网 IP，它们的时间戳不统一（快慢不一），服务端会因时间戳回退直接丢包，导致连接失败；故 recycle 在 4.12 内核已删除，reuse 也建议仅在客户端侧开启。</li></ul></li></ul></li></ul><h3 id="q-21-24" tabindex="-1">3. TCP 拥塞控制（慢启动/拥塞避免/快重传/快恢复）？ <a class="header-anchor" href="#q-21-24" aria-label="Permalink to &quot;3. TCP 拥塞控制（慢启动/拥塞避免/快重传/快恢复）？ {#q-21-24}&quot;">​</a></h3><p>慢启动指数探窗，遇丢包进拥塞避免线性增；快重传/快恢复在收到 3 个重复 ACK 时降窗而非归零。</p><ul><li>目标是&quot;探测可用带宽又不打爆网络&quot;。</li><li>与流量控制（滑动窗口，防接收方溢出）是两回事。</li></ul><h4 id="f-21-23" tabindex="-1">追问： <a class="header-anchor" href="#f-21-23" aria-label="Permalink to &quot;追问： {#f-21-23}&quot;">​</a></h4><ul><li>追问1：BBR 和 Reno/CUBIC 思路根本区别？你们内网/跨云用了哪种？ <ul><li><strong>答</strong>：Reno/CUBIC 是基于&quot;丢包&quot;的信号——丢包才降窗，在高 BDP 长肥管道或轻微丢包下会误判、压不满带宽。BBR 基于&quot;测量&quot;带宽与 RTT，主动探测最大带宽和最小延迟来定发送窗口，不把丢包当拥塞唯一信号。 <ul><li>取舍：跨云/跨公网长链路（对象存储、模型推理网关）倾向开 BBR；内网低延迟链路 CUBIC 已够，没必要。</li></ul></li></ul></li><li>追问2：快恢复和&quot;超时重传归零&quot;的差别在实战延迟上体现为什么？ <ul><li><strong>答</strong>：收到 3 个重复 ACK 触发快重传+快恢复，窗口只降到 ssthresh（一半），吞吐平滑、延迟毛刺小；超时（既无 ACK 也无重复 ACK）说明可能整段丢失，窗口归零进慢启动，从 1 起飞恢复慢。 <ul><li>实战体现：一次超时可能让用户感知到几百毫秒到秒级停顿（长尾），快恢复则几乎无感。</li></ul></li></ul></li></ul><h3 id="q-21-25" tabindex="-1">4. TCP 滑动窗口与流量控制？ <a class="header-anchor" href="#q-21-25" aria-label="Permalink to &quot;4. TCP 滑动窗口与流量控制？ {#q-21-25}&quot;">​</a></h3><p>接收方在 ACK 里带窗口大小，发送方据此控制未确认数据量，防接收方缓冲区溢出。</p><ul><li>糊涂窗口综合征：小窗口小数据导致低效；用 Nagle / Clark 算法缓解。</li><li>滑动窗口是&quot;流控&quot;，拥塞窗口是&quot;拥塞控&quot;，取二者小值为发送上限。</li></ul><h4 id="f-21-24" tabindex="-1">追问： <a class="header-anchor" href="#f-21-24" aria-label="Permalink to &quot;追问： {#f-21-24}&quot;">​</a></h4><ul><li>追问1：Nagle 算法和 TCP_NODELAY 你们在 SSE 流式下怎么设？设错会怎样？ <ul><li><strong>答</strong>：SSE 要低延迟推 token，服务端 socket 设 <code>TCP_NODELAY</code> 关闭 Nagle，避免小包等待合并造成几十毫秒级延迟累积。 <ul><li>设错（开着 Nagle）：每个 token 小包被攒到 MSS 或等 ACK，流式&quot;一卡一卡&quot;；全关 Nagle 会增包量，所以只在对实时敏感的推送通道关，普通请求不关。</li></ul></li></ul></li><li>追问2：接收窗口被填满了，发送方是阻塞还是丢数据？应用层感知得到吗？ <ul><li><strong>答</strong>：是阻塞（TCP 流控）：发送方收到零窗口通告后停止发送，数据暂存发送缓冲区，不会丢；接收方消费后回&quot;窗口更新&quot;报文恢复。 <ul><li>应用层感知：write 在阻塞模式会阻塞、非阻塞返回 EAGAIN，需靠背压处理，否则数据堆在应用缓冲可能 OOM。</li></ul></li></ul></li></ul><h3 id="q-21-26" tabindex="-1">5. TCP 和 UDP 区别？什么场景用 UDP？ <a class="header-anchor" href="#q-21-26" aria-label="Permalink to &quot;5. TCP 和 UDP 区别？什么场景用 UDP？ {#q-21-26}&quot;">​</a></h3><p>TCP 可靠有序有连接；UDP 不可靠无连接但低延迟、支持广播/多播。</p><ul><li>音视频、游戏、DNS 查询、内网高吞吐用 UDP；可靠传输用 TCP。</li><li>QUIC 在 UDP 上自实现可靠，兼顾二者。</li></ul><h4 id="f-21-25" tabindex="-1">追问： <a class="header-anchor" href="#f-21-25" aria-label="Permalink to &quot;追问： {#f-21-25}&quot;">​</a></h4><ul><li>追问1：你们 RAG 流水线里有没有用 UDP 的场景？为什么没有？ <ul><li><strong>答</strong>：核心链路基本没有。RAG 是&quot;检索+推理&quot;链路，文档/向量召回、模型请求、token 流都要求可靠、有序、低错误，TCP/HTTP 更省心。 <ul><li>UDP 只在&quot;丢了无所谓&quot;的场景用：监控埋点（metrics 上报 StatsD）、内网探活；核心链路不碰。</li></ul></li></ul></li><li>追问2：UDP 自己想做可靠传输，要补哪些机制（序号/ACK/重传）？ <ul><li><strong>答</strong>：至少补：①序号(seq) 给每个包编号，保证有序与去重；②ACK/NACK 让接收方确认；③超时重传；④滑动窗口做流控；⑤必要时加拥塞控制。 <ul><li>QUIC 就是这么干的——在 UDP 上重做可靠+拥塞+多路复用，等于自己造了个轻量 TCP。</li></ul></li></ul></li></ul><h3 id="q-21-27" tabindex="-1">6. HTTP 与 HTTPS 区别？TLS 握手过程？ <a class="header-anchor" href="#q-21-27" aria-label="Permalink to &quot;6. HTTP 与 HTTPS 区别？TLS 握手过程？ {#q-21-27}&quot;">​</a></h3><p>HTTPS = HTTP + TLS，多了身份认证、加密、完整性。</p><ul><li>TLS1.3 握手：ClientHello→ServerHello(+证书)→密钥交换→完成，1-RTT 建密。</li><li>证书链校验 + 非对称协商对称密钥，之后用对称加密传输。</li></ul><h4 id="f-21-26" tabindex="-1">追问： <a class="header-anchor" href="#f-21-26" aria-label="Permalink to &quot;追问： {#f-21-26}&quot;">​</a></h4><ul><li>追问1：TLS1.3 相比 1.2 少了哪次往返？对你们首屏/首字延迟影响多大？ <ul><li><strong>答</strong>：1.2 需 2-RTT（ClientHello→ServerHello+证书+密钥参数→密钥确认），1.3 把密钥交换参数并进 ClientHello/ServerHello，做到 1-RTT，且支持 0-RTT 会话恢复。 <ul><li>影响：省一个 RTT（通常 30–100ms 视距离）；SSE 首字延迟上把 TLS 建连从 2 次砍到 1 次，配合 HTTP/2 复用后续请求近乎零握手成本。</li></ul></li></ul></li><li>追问2：证书过期/链不完整，客户端报什么错？服务端怎么监控证书有效期？ <ul><li><strong>答</strong>：客户端报证书过期/不受信/链校验失败（浏览器 <code>NET::ERR_CERT_*</code>、curl 60/77/82）。服务端监控：定时用 <code>openssl s_client -servername</code> 取 <code>notAfter</code>，Prometheus 告警&quot;剩余&lt;30 天&quot;。 <ul><li>我们用 ACME（Let&#39;s Encrypt）自动续期 + 续期失败告警，避免人工漏续导致线上证书过期。</li></ul></li></ul></li></ul><h3 id="q-21-28" tabindex="-1">7. HTTP/1.1、HTTP/2、HTTP/3 核心区别？ <a class="header-anchor" href="#q-21-28" aria-label="Permalink to &quot;7. HTTP/1.1、HTTP/2、HTTP/3 核心区别？ {#q-21-28}&quot;">​</a></h3><p>1.1 队头阻塞+文本；2 多路复用+头部压缩(HPACK)+单连接；3 基于 QUIC(UDP) 彻底解决队头阻塞。</p><ul><li>2 用一条 TCP 连接并发流；3 把可靠搬进 UDP 层，连接迁移更稳。</li><li>碳管家前端用 HTTP/2，边缘可上 HTTP/3。</li></ul><h4 id="f-21-27" tabindex="-1">追问： <a class="header-anchor" href="#f-21-27" aria-label="Permalink to &quot;追问： {#f-21-27}&quot;">​</a></h4><ul><li>追问1：HTTP/2 多路复用为什么还受 TCP 队头阻塞影响？HTTP/3 怎么解决？ <ul><li><strong>答</strong>：HTTP/2 在一条 TCP 连接上开多个 stream 并发，但底层一条 TCP 流若丢一个包，整连接的重传会卡住所有 stream（队头阻塞在 TCP 层）。 <ul><li>HTTP/3 把传输搬去 QUIC(UDP)，每个 stream 独立可靠，单 stream 丢包只重传该 stream，其他 stream 不受影响，彻底解耦。</li></ul></li></ul></li><li>追问2：你们网关(Nginx) 配了 HTTP/2 吗？配了但客户端仍是 1.1 常见原因？ <ul><li><strong>答</strong>：配了（<code>listen 443 ssl http2</code>）。客户端仍是 1.1 常见原因：①前端走 HTTP(80 被 301) 或代理链某跳降级；②反向代理/ALB 未开 h2；③ALPN 协商失败（证书/TLS 配置问题）；④老 SDK/curl 默认不协商 h2。 <ul><li>排查看响应协议头是否为 <code>HTTP/2.0</code> 或连接是否 <code>h2</code>。</li></ul></li></ul></li></ul><h3 id="q-21-29" tabindex="-1">8. 长连接/短连接、心跳机制？ <a class="header-anchor" href="#q-21-29" aria-label="Permalink to &quot;8. 长连接/短连接、心跳机制？ {#q-21-29}&quot;">​</a></h3><p>短连接每请求建断，开销大；长连接复用，省握手；心跳保活、探测死连接。</p><ul><li>TCP Keepalive 太粗，业务层常自用心跳（如 WebSocket ping/pong）。</li><li>碳管家 SSE/WS 用应用层心跳，断线自动重连。</li></ul><h4 id="f-21-28" tabindex="-1">追问： <a class="header-anchor" href="#f-21-28" aria-label="Permalink to &quot;追问： {#f-21-28}&quot;">​</a></h4><ul><li>追问1：TCP Keepalive 默认两小时，为什么不够？应用心跳间隔怎么定？ <ul><li><strong>答</strong>：默认 7200s 空闲才发探测、3 次×75s，死连接要两小时才发现，长连接业务不可接受。应用心跳按&quot;故障检测时效&quot;定：内网 WS/SSE 我们 15–30s 一次 ping/pong，容忍 2–3 次失败判定死亡；公网可更密，一般 20–60s。</li></ul></li><li>追问2：心跳太频繁浪费带宽，太稀发现死连接慢，你们怎么取舍？ <ul><li><strong>答</strong>：按&quot;可容忍失联时长&quot;反推间隔：能接受 1 分钟发现断线 → 间隔 20s、容忍 2 次失败。SSE 用 30s 心跳 + 应用层 1 次超时即标记，并依赖 SSE 自带重连。 <ul><li>优化：用小包（几字节）+ 仅在空闲时发（有数据流量就不发额外心跳），兼顾时效与带宽成本。</li></ul></li></ul></li></ul><h3 id="q-21-30" tabindex="-1">9. TCP 粘包/拆包？怎么解决？ <a class="header-anchor" href="#q-21-30" aria-label="Permalink to &quot;9. TCP 粘包/拆包？怎么解决？ {#q-21-30}&quot;">​</a></h3><p>TCP 是字节流无消息边界，发送方的多次 write 可能被合并或拆分。</p><ul><li>解决：定长、分隔符、长度字段(头带 body 长度)——长度字段最常用。</li><li>Netty 用 LengthFieldBasedFrameDecoder 处理。</li></ul><h4 id="f-21-29" tabindex="-1">追问： <a class="header-anchor" href="#f-21-29" aria-label="Permalink to &quot;追问： {#f-21-29}&quot;">​</a></h4><ul><li>追问1：为什么 UDP 没有粘包问题？它有没有别的问题（截断）？ <ul><li><strong>答</strong>：UDP 是数据报，内核给应用层的是&quot;一个完整 datagram&quot;，有消息边界，所以不粘不拆。但它有&quot;截断&quot;问题：recv 缓冲小于 datagram 时多余数据被丢弃（返回 <code>MSG_TRUNC</code> 或静默丢）。 <ul><li>UDP 应用要足够大的接收缓冲且知道最大包长，否则会静默丢数据。</li></ul></li></ul></li><li>追问2：你们自定义 RPC/协议时用长度字段还是分隔符？为什么？ <ul><li><strong>答</strong>：用长度字段（4 字节 body length + body），不用分隔符。原因：①二进制安全，body 出现分隔符字节不会误判边界；②可预读长度后精准分配缓冲、直接 seek；③与 Netty <code>LengthFieldBasedFrameDecoder</code> 天然配合。 <ul><li>分隔符只适合纯文本且能保证内容不含分隔符的简单场景。</li></ul></li></ul></li></ul><h3 id="q-21-31" tabindex="-1">10. DNS 解析过程？污染/劫持？ <a class="header-anchor" href="#q-21-31" aria-label="Permalink to &quot;10. DNS 解析过程？污染/劫持？ {#q-21-31}&quot;">​</a></h3><p>递归查询：本地→递归解析→根→顶级域→权威，逐级拿到 IP 并缓存。</p><ul><li>污染/劫持：中间篡改响应；缓解：DoH/DoT 加密、靠谱公共 DNS。</li><li>服务内部用服务发现(如 K8s DNS) 而非公网 DNS。</li></ul><h4 id="f-21-30" tabindex="-1">追问： <a class="header-anchor" href="#f-21-30" aria-label="Permalink to &quot;追问： {#f-21-30}&quot;">​</a></h4><ul><li>追问1：DNS 缓存 TTL 设太长更新慢、太短压力大，你们怎么定？ <ul><li><strong>答</strong>：对外权威记录（API 域名）TTL 设 60–300s，兼顾&quot;故障时快速切流量&quot;与&quot;缓存命中&quot;；变化极少的记录（根/证书相关）可长。 <ul><li>内部 K8s 服务发现靠 CoreDNS（常 30s 或 0），走 svc 抽象而非手动改 DNS，TTL 不是主要切换手段。</li></ul></li></ul></li><li>追问2：K8s 里 Service 名解析走的是什么 DNS？Pod 重建 IP 变了怎么感知？ <ul><li><strong>答</strong>：走 CoreDNS（集群内 DNS），Service 名解析为稳定的 ClusterIP，Pod 通过 svc 名访问，不关心 Pod IP。Pod 重建 IP 变了，但 svc 的 ClusterIP 与 endpoints 由 endpoint controller/kube-proxy 自动更新。 <ul><li>客户端连 svc 名无感；只有直连 Pod IP 才需自己处理 IP 变化。</li></ul></li></ul></li></ul><h3 id="q-21-32" tabindex="-1">11. ARP 协议作用？ARP 欺骗？ <a class="header-anchor" href="#q-21-32" aria-label="Permalink to &quot;11. ARP 协议作用？ARP 欺骗？ {#q-21-32}&quot;">​</a></h3><p>ARP 把 IP 解析为 MAC，局域网通信靠 MAC；欺骗是伪造 ARP 响应劫持流量。</p><ul><li>防御：静态绑定、交换机端口安全、网络隔离。</li><li>云环境多在 VPC 内，风险由云平台承担。</li></ul><h4 id="f-21-31" tabindex="-1">追问： <a class="header-anchor" href="#f-21-31" aria-label="Permalink to &quot;追问： {#f-21-31}&quot;">​</a></h4><ul><li>追问1：同网段两台机器通信，包为什么要先 ARP 拿到 MAC 才发？ <ul><li><strong>答</strong>：二层以太帧靠 MAC 寻址，IP 只是三层逻辑地址；同网段下一跳就是目标主机，必须把目标 IP 解析成 MAC 才能封装以太帧发出去。ARP 表有缓存，命中就不发请求；跨网段则是发给网关 MAC。</li></ul></li><li>追问2：云上容器网络(如 Cilium) 还走传统 ARP 吗？eBPF 怎么绕过？ <ul><li><strong>答</strong>：传统 flannel/vxlan 仍依赖 ARP；Cilium 用 eBPF 绕过内核协议栈与 ARP：在宿主机用 BPF 程序直接做&quot;Pod IP→对端节点/host&quot;的路由与封装（基于已同步的端点表），不广播 ARP 请求。 <ul><li>收益：降延迟、去 ARP 风暴，且能在 socket 层做 L3/L4 策略。</li></ul></li></ul></li></ul><h3 id="q-21-33" tabindex="-1">12. 负载均衡：LVS/Nginx、四层七层区别？ <a class="header-anchor" href="#q-21-33" aria-label="Permalink to &quot;12. 负载均衡：LVS/Nginx、四层七层区别？ {#q-21-33}&quot;">​</a></h3><p>四层(LVS/IPVS) 按 IP+端口转发，快、无脑；七层(Nginx) 看 HTTP 内容，可路由/改写。</p><ul><li>选择：外层四层扛量，内层七层做业务路由。</li><li>碳管家入口 LVS/ALB 四层 + Nginx/Spring Cloud Gateway 七层。</li></ul><h4 id="f-21-32" tabindex="-1">追问： <a class="header-anchor" href="#f-21-32" aria-label="Permalink to &quot;追问： {#f-21-32}&quot;">​</a></h4><ul><li>追问1：四层负载均衡怎么保证同一客户端落到同一后端（会话保持）？ <ul><li><strong>答</strong>：LVS/IPVS 按&quot;源 IP 哈希&quot;或&quot;源 IP+端口&quot;做一致性哈希，把同一客户端映射到固定 RS；也有基于连接调度的 persistence 表。 <ul><li>注意：源 IP 在 NAT/代理后易集中导致倾斜；更细的会话保持可在七层（Nginx）用 cookie 插入实现。</li></ul></li></ul></li><li>追问2：七层网关做 TLS 终结，后端用 HTTP 明文，安全吗？内网怎么看？ <ul><li><strong>答</strong>：公网绝不行；内网可接受但有前提：TLS 在网关终结，后端只走内网（VPC/overlay），网络隔离 + 禁止公网直连后端，明文只在内网一跳。 <ul><li>风险：内网被渗透后流量可抓；我们内网也倾向 mTLS（服务网格）或至少限制后端只收网关来源 IP。</li></ul></li></ul></li></ul><h3 id="q-21-34" tabindex="-1">13. 从输入 URL 到页面返回，完整过程？ <a class="header-anchor" href="#q-21-34" aria-label="Permalink to &quot;13. 从输入 URL 到页面返回，完整过程？ {#q-21-34}&quot;">​</a></h3><p>DNS→TCP 握手→TLS 握手→发请求→网关/服务处理→DB/缓存→响应→浏览器渲染。</p><ul><li>每个环节都有延迟，优化点分散在 CDN、连接复用、缓存、并行。</li><li>对 AI 助手：还有模型推理这一长耗时环节。</li></ul><h4 id="f-21-33" tabindex="-1">追问： <a class="header-anchor" href="#f-21-33" aria-label="Permalink to &quot;追问： {#f-21-33}&quot;">​</a></h4><ul><li>追问1：你们首字延迟(TTFT) 在这条链路里主要耗在哪一段？怎么拆出来看？ <ul><li><strong>答</strong>：主要耗在&quot;网关→推理服务→模型首 token&quot;这段，DNS/握手通常几 ms~几十 ms 占比小。拆分：网关计时请求到达→转发；推理侧计时排队→prefill 完成→首 token 出。 <ul><li>用 OpenTelemetry 链路打点，分别看网络 RTT、队列等待、模型 prefill 耗时，定位是带宽/排队还是算力瓶颈。</li></ul></li></ul></li><li>追问2：CDN 对动态 API（如问答）有用吗？还是只对静态资源有用？ <ul><li><strong>答</strong>：纯动态问答（每次不同、不可缓存）CDN 帮不上缓存，但仍有用：①边缘就近 TLS 终止 + 连接复用，省首跳 RTT；②边缘做限流/鉴权/防刷；③可缓存静态资源（前端包、tokenizer 文件）加速。 <ul><li>动态内容主要靠就近接入 + 链路优化，而非缓存命中。</li></ul></li></ul></li></ul><h3 id="q-21-35" tabindex="-1">14. cookie/session/token 区别？为什么 JWT 无状态？ <a class="header-anchor" href="#q-21-35" aria-label="Permalink to &quot;14. cookie/session/token 区别？为什么 JWT 无状态？ {#q-21-35}&quot;">​</a></h3><p>Session 在服务端存状态，Cookie 带 sessionId；Token(JWT) 把状态编码进令牌，服务端不存，无状态。</p><ul><li>无状态利于水平扩展，但令牌吊销难、体积大。</li><li>碳管家用网关统一鉴权，JWT/API Key 校验。</li></ul><h4 id="f-21-34" tabindex="-1">追问： <a class="header-anchor" href="#f-21-34" aria-label="Permalink to &quot;追问： {#f-21-34}&quot;">​</a></h4><ul><li>追问1：JWT 没法主动吊销，你们怎么处理&quot;用户登出/封禁&quot;立即生效？ <ul><li><strong>答</strong>：几招组合：①短 exp（15–30min）+ 刷新 token，封禁后旧 access 很快失效；②维护 Redis &quot;黑名单/版本号&quot;，登出/封禁时写 jti 或 token 版本，网关校验时查一下（小成本换可控）；③JWT 内带&quot;用户 token 版本号&quot;，服务端比对不一致即拒。</li></ul></li><li>追问2：Session 在分布式多实例下存哪？Redis 集中存 session 有什么坑？ <ul><li><strong>答</strong>：集中存 Redis（spring-session），多实例共享。坑：①Redis 挂则会话全失效→需高可用+本地降级；②序列化/反序列化开销、大 session 占内存；③每次请求多一跳网络延迟；④过期与&quot;滑动过期&quot;配不好用户被莫名踢出；⑤热 key 集中要分片。我们更偏无状态 JWT 减少此依赖。</li></ul></li></ul><h3 id="q-21-36" tabindex="-1">15. WebSocket 与 HTTP 长轮询区别？SSE 是什么？ <a class="header-anchor" href="#q-21-36" aria-label="Permalink to &quot;15. WebSocket 与 HTTP 长轮询区别？SSE 是什么？ {#q-21-36}&quot;">​</a></h3><p>长轮询是&quot;挂着等&quot;，仍走 HTTP 请求；WebSocket 是独立全双工长连；SSE 是服务端→客户端的单向流式（基于 HTTP）。</p><ul><li>双向实时用 WS，单向推流用 SSE 更简单（碳管家流式回答用 SSE）。</li><li>SSE 自带重连，纯文本流，和 LLM token 流天然契合。</li></ul><h4 id="f-21-35" tabindex="-1">追问： <a class="header-anchor" href="#f-21-35" aria-label="Permalink to &quot;追问： {#f-21-35}&quot;">​</a></h4><ul><li>追问1：SSE 和 WebSocket 在你们&quot;流式回答&quot;场景为什么选 SSE 不选 WS？ <ul><li><strong>答</strong>：流式回答本质是&quot;服务端→客户端单向推 token&quot;，SSE 天然单向、基于 HTTP、自带 EventSource 自动重连、纯文本好调试，和 LLM token 流完美契合。WS 是双向全双工，我们要的只是下行，双向反而多维护连接状态与心跳复杂度、且 Nginx 配置更挑剔。下行单向场景 SSE 性价比最高。</li></ul></li><li>追问2：SSE 在 Nginx/Gateway 下被缓冲导致不流式，怎么排查（和之前哪题呼应）？ <ul><li><strong>答</strong>：排查：①Nginx 默认 <code>proxy_buffering on</code> 会攒 buffer 才下发，需关掉（<code>proxy_buffering off;</code> 或响应头 <code>X-Accel-Buffering: no</code>）；②网关/Spring 输出流是否被 Collectors 缓冲、是否及时 flush；③确认 <code>Content-Type: text/event-stream</code> 且禁用 gzip 缓冲。呼应第 4 题 TCP_NODELAY/流控——本质都是&quot;中间层缓冲破坏实时性&quot;，要显式关缓冲+及时 flush。</li></ul></li></ul>`,219)])])}const P=i(a,[["render",r]]);export{h as __pageData,P as default};
